import React, { useState } from 'react';
import './Admin.css';

const AdminDashboard = () => {
    // 3. DEALER_ID_REVIEWS DATA
    const [allReviews, setAllReviews] = useState([
        { id: 1, dealer_id: 1, user: "Kelebogile M.", comment: "Great stock selection!", status: "Approved" },
        { id: 2, dealer_id: 2, user: "Pieter S.", comment: "Service was a bit slow today.", status: "Pending" },
        { id: 3, dealer_id: 1, user: "Thandi N.", comment: "The lilac theme is beautiful.", status: "Pending" },
        { id: 4, dealer_id: 3, user: "John Doe", comment: "Average experience.", status: "Approved" }
    ]);

    const handleDelete = (id) => {
        setAllReviews(allReviews.filter(review => review.id !== id));
    };

    return (
        <div className="dashboard-container">
            <header className="admin-header">
                <h1 className="cyber-title">Admin Control Panel</h1>
                <div className="admin-stats" style={{ display: 'flex', gap: '20px', margin: '20px 0' }}>
                    <div className="dealer-card" style={{ flex: 1 }}>
                        <p>Total Reviews</p>
                        <h2 style={{ color: '#E0B0FF' }}>{allReviews.length}</h2>
                    </div>
                    <div className="dealer-card" style={{ flex: 1 }}>
                        <p>Pending Moderation</p>
                        <h2 style={{ color: '#ffa500' }}>
                            {allReviews.filter(r => r.status === "Pending").length}
                        </h2>
                    </div>
                </div>
            </header>

            <div className="glass-card" style={{ padding: '25px', overflowX: 'auto' }}>
                <h3 style={{ color: '#E0B0FF', marginBottom: '15px' }}>Dealer Review Moderation</h3>
                <table style={{ width: '100%', color: 'white', borderCollapse: 'collapse' }}>
                    <thead>
                        <tr style={{ borderBottom: '2px solid #444', textAlign: 'left', color: '#E0B0FF' }}>
                            <th style={{ padding: '12px' }}>Dealer ID</th>
                            <th>Reviewer</th>
                            <th>Comment</th>
                            <th>Status</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {allReviews.map(review => (
                            <tr key={review.id} style={{ borderBottom: '1px solid #222' }}>
                                <td style={{ padding: '15px' }}>{review.dealer_id}</td>
                                <td>{review.user}</td>
                                <td style={{ maxWidth: '300px' }}>{review.comment}</td>
                                <td>
                                    <span style={{ 
                                        color: review.status === "Approved" ? "#00ff00" : "#ffa500",
                                        fontSize: '0.8rem',
                                        fontWeight: 'bold'
                                    }}>
                                        {review.status}
                                    </span>
                                </td>
                                <td>
                                    <button className="cyber-button" style={{ padding: '5px 10px', fontSize: '0.7rem', marginRight: '5px' }}>
                                        Approve
                                    </button>
                                    <button 
                                        className="logout-btn" 
                                        style={{ padding: '5px 10px', fontSize: '0.7rem' }}
                                        onClick={() => handleDelete(review.id)}
                                    >
                                        Delete
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default AdminDashboard;
